```typescript
function solve(grid: number[][], k: number): number {
    let count = 0;
    const m = grid.length;
    const n = grid[0].length;

    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            if (grid[i][j] > 0) {
                let sum = 0;
                let queue: [number, number][] = [[i, j]];

                while (queue.length > 0) {
                    let [x, y] = queue.shift()!;
                    sum += grid[x][y];
                    grid[x][y] = 0;

                    const directions = [[-1, 0], [1, 0], [0, -1], [0, 1]];
                    for (let [dx, dy] of directions) {
                        let nx = x + dx;
                        let ny = y + dy;
                        if (nx >= 0 && nx < m && ny >= 0 && ny < n && grid[nx][ny] > 0) {
                            queue.push([nx, ny]);
                        }
                    }
                }

                if (sum % k === 0) {
                    count++;
                }
            }
        }
    }

    return count;
}
